$(".filter__show").click(function() {
    $(this).toggleClass("filter__show--active")
    $(this).siblings(".filter__hidden").slideToggle()
})
$("._toggle-filter").click(function() {
    $("body").toggleClass("fixed-body")
    $("body").toggleClass("_show-filter")
})

$("._add-to-cart").click(function() {
    $(".product-cart").addClass("_added")
})

cartCalc()

function cartCalc() {
    $('.cartcalc .ccalc-minus').click(function() {
        let a = $(this).closest('.cartcalc').find('input').val();
        if (a > 1) {
            let b = +a - 1;
            $(this).closest('.cartcalc').find('input').val(b);
        } else {
            $(this).closest('.cartcalc').find('input').val(a);
            $(".product-cart").removeClass("_added")
        }
    });
    $('.cartcalc .ccalc-plus').click(function() {
        let a = $(this).closest('.cartcalc').find('input').val();
        let b = +a + 1;
        $(this).closest('.cartcalc').find('input').val(b);
    });
}
